-- ============================================================
-- CAPSTONE PROJECT: Banking - Transaction Monitoring
-- Database Setup Script
-- Data Analyst Training Program - Weeks 10-12
-- ============================================================

DROP DATABASE IF EXISTS capstone_banking;
CREATE DATABASE capstone_banking;
USE capstone_banking;

-- ============================================================
-- TABLE 1: Customers (1,500 records)
-- ============================================================
CREATE TABLE Customers (
    Customer_ID VARCHAR(10) PRIMARY KEY,
    Customer_Name VARCHAR(100) NOT NULL,
    City VARCHAR(50),
    Account_Type VARCHAR(20),
    Account_Open_Date DATE
);




-- ============================================================
-- TABLE 2: Transactions (10,000 records)
-- ============================================================
CREATE TABLE Transactions (
    Transaction_ID VARCHAR(15) PRIMARY KEY,
    Customer_ID VARCHAR(10),
    Transaction_Date DATE,
    Amount DECIMAL(12, 2),
    Channel VARCHAR(20),
    Transaction_Type VARCHAR(20),
    Branch VARCHAR(30),
    Status VARCHAR(20),
    FOREIGN KEY (Customer_ID) REFERENCES Customers(Customer_ID)
);





















-- ============================================================
-- VERIFICATION QUERIES
-- ============================================================
SELECT 'Customers' AS Table_Name, COUNT(*) AS Row_Count FROM Customers
UNION ALL
SELECT 'Transactions', COUNT(*) FROM Transactions;

-- Quick preview
SELECT * FROM Customers LIMIT 5;
SELECT * FROM Transactions LIMIT 5;
/*Step 5: Explore each table individually using SELECT, COUNT, and DISTINCT to understand the data--*/
/*How many customers and transactions are in the database?*/
SELECT COUNT(*) FROM Customers;
SELECT COUNT(*) FROM Transactions;
/*What are the distinct values for Channel, Transaction_Type, Status, and Account_Type*/
SELECT DISTINCT Channel FROM Transactions;
SELECT DISTINCT Transaction_Type FROM Transactions;
SELECT DISTINCT Status FROM Transactions;
SELECT DISTINCT Account_Type FROM Customers;
/*What is the date range of the transaction data*/
SELECT
MIN(Transaction_Date) AS start_date,
MAX(Transaction_Date) AS end_date
FROM Transactions;
/*Write a JOIN query to combine customer details with their transactions*/
SELECT
    t.Transaction_ID,
    t.Transaction_Date,
    t.Amount,
    t.Channel,
    t.Transaction_Type,
    t.Branch,
    t.Status,
    c.Customer_ID,
    c.Customer_Name,
    c.City,
    c.Account_Type,
    c.Account_Open_Date
FROM Transactions t
JOIN Customers c
ON t.Customer_ID = c.Customer_ID;
/*Which cities have the most customers? The most transaction volume?*/
SELECT
c.City,
COUNT(DISTINCT c.Customer_id) AS Total_Customers,
SUM(t.Amount) AS Total_volume
FROM Customers c
JOIN Transactions t ON c.Customer_ID = t.Customer_ID
GROUP BY c.City
ORDER BY Total_volume DESC;
/*How do transaction patterns differ by Account_Type*/
SELECT
c.Account_Type,
COUNT(t.Transaction_ID) AS Transaction_Count, 
SUM(t.Amount) AS Total_Spent,
AVG(t.Amount) AS Avg_Transaction_Value
FROM Customers c
JOIN Transactions t ON c.Customer_ID = t.Customer_ID
GROUP BY c.Account_Type;
/*Total transaction count and amount by Channel*/
SELECT
Channel,
count(*) AS Transactions_count,
SUM(Amount) AS Total_Transaction,
AVG(Amount) AS Avg_Transaction
FROM Transactions
GROUP BY Channel;
/*Average transaction amount by Transaction_Type*/
SELECT
Transaction_Type,
COUNT(DISTINCT Transaction_Type) AS Total_Transactions,
AVG(Amount) AS Avg_Amount
FROM Transactions
GROUP BY Transaction_Type
ORDER BY Avg_Amount DESC;
/*Monthly transaction volume trends (GROUP BY month)*/
SELECT
Month(Transaction_Date) AS Transaction_Month,
COUNT(Transaction_ID) AS Transaction_count,
SUM(Amount) AS Total_volume
FROM Transactions
GROUP BY Transaction_Month
ORDER BY Transaction_Month;
/*Branches with total transaction amount exceeding a threshold (HAVING)*/
SELECT
Branch,
SUM(Amount) AS Total_Transaction_Amount
FROM Transactions
WHERE Branch IS NOT NULL
GROUP BY Branch
HAVING Total_Transaction_Amount > 500000
ORDER BY Total_Transaction_Amount;




